import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        for (int i = 0; i < t; i++) {
            int n = scanner.nextInt();
            int m = scanner.nextInt();
            int[] spots = new int[n];
            for (int j = 0; j < n; j++) {
                spots[j] = j + 1;
            }
            int minWireLength = 1000000;
            do {
                int wireLength = calculateWireLength(spots, n);
                if (wireLength < minWireLength) {
                    minWireLength = wireLength;
                }
            } while (nextPermutation(spots));
            if (m < minWireLength) {
                System.out.println(-1);
            } else {
                System.out.println(m - minWireLength);
            }
        }
    }

    public static int calculateWireLength(int[] spots, int n) {
        int wireLength = 0;
        for (int i = 0; i < n; i++) {
            if (i == 0) {
                wireLength += spots[i];
            } else {
                wireLength += Math.abs(spots[i] - spots[i-1]);
            }
        }
        wireLength += (n + 1) - spots[n-1];
        return wireLength;
    }

    public static boolean nextPermutation(int[] array) {
        int i = array.length - 2;
        while (i >= 0 && array[i] >= array[i + 1]) {
            i--;
        }
        if (i < 0) {
            return false;
        }
        int j = array.length - 1;
        while (j > i && array[j] <= array[i]) {
            j--;
        }
        swap(array, i, j);
        reverse(array, i + 1);
        return true;
    }

    public static void swap(int[] array, int i, int j) {
        int temp = array[i];
        array[i] = array[j];
        array[j] = temp;
    }

    public static void reverse(int[] array, int start) {
        int i = start;
        int j = array.length - 1;
        while (i < j) {
            swap(array, i, j);
            i++;
            j--;
        }
    }
}

